public OrderDataBean buy(String userID, String symbol, double quantity, int orderProcessingMode) throws Exception {
    if (quantity <= 0) {
        throw new Exception("Quantity must be greater than zero");
    }

    AccountDataBean accountData = getAccountData(userID);
    if (accountData == null) {
        throw new Exception("Invalid user ID");
    }

    QuoteDataBean quoteData = getQuote(symbol);
    if (quoteData == null) {
        throw new Exception("Invalid symbol");
    }

    OrderDataBean orderData = createOrder(accountData, quoteData, null, "buy", quantity);

    switch (orderProcessingMode) {
        case TradeConfig.SYNCH:
            orderData.setOrderStatus("completed");
            break;
        case TradeConfig.ASYNCH:
            orderData.setOrderStatus("open");
            queueOrder(orderData.getOrderID(), false);
            break;
        case TradeConfig.ASYNCH_2PHASE:
            orderData.setOrderStatus("queued");
            queueOrder(orderData.getOrderID(), true);
            break;
        default:
            throw new Exception("Invalid order processing mode");
    }

    orderData.setOrderFee(TradeConfig.getOrderFee("buy"));
    return orderData;
}
